import{_ as e,p as i,q as l,a1 as t}from"./framework-e0dd9823.js";const h={},r=t('<h1 id="特殊疑问句" tabindex="-1"><a class="header-anchor" href="#特殊疑问句" aria-hidden="true">#</a> 特殊疑问句</h1><p>特殊疑问句是英语中以特殊疑问词开头，对句中某一成分提问的句子（以特殊疑问词（组）开头的以寻求信息为目的的疑问句）。</p><p>常用的疑问词有</p><table><thead><tr><th>疑问词</th><th>意思</th></tr></thead><tbody><tr><td>where</td><td>在哪里</td></tr><tr><td>what</td><td>什么</td></tr><tr><td>why</td><td>为什么</td></tr><tr><td>whose</td><td>谁的</td></tr><tr><td>when</td><td>什么时候</td></tr><tr><td>whom</td><td>谁</td></tr><tr><td>who</td><td>谁</td></tr><tr><td>which</td><td>哪一个</td></tr><tr><td>how</td><td>如何，怎样</td></tr></tbody></table><h2 id="where-在哪里-哪里" tabindex="-1"><a class="header-anchor" href="#where-在哪里-哪里" aria-hidden="true">#</a> where 在哪里，哪里</h2><ol><li>做地点状语</li></ol><p>where 做地点状语一般只能出现的主谓宾的句子，主系表不可以。</p><p>做地点状语，句型：“Where + 主语 + 谓语 + 宾语”。疑问词后面必须使用一般疑问句，所以 where 后面的主谓宾必须是一般疑问句的结构。</p><p>例句：</p><ul><li>Where do you learn English?（一般现在时态）</li><li>Where do they work?</li><li>Where do your friends sell clothes?</li><li>Where does Nick teach English?（单三）</li><li>Where does she bake sweet potatoes every day?</li><li>Where does he run every morning?</li><li>Where will she buy a house next year?（一般将来时态）</li><li>Where will you business next month?</li><li>Where will your aunt dance tonight?</li><li>Where is she going to look for a job next month?(be going to)</li><li>Where am I going to teach English in the future?</li><li>Where are my friends going to swim tomorrow?</li><li>Where is she drinking wine now?（现在进行时态）</li><li>Where are they running now?</li><li>Where is Nick baking sweet potatoes?</li><li>Where has she gone to?（现在完成时态）</li><li>Where has she bought a house?</li><li>Where have they learned English for year?</li></ul><ol start="2"><li>作表语</li></ol><p>句型：“Where + be + 主语 + 状语？”，因为 where 本身是疑问词，所以必须放开头，然后，有因为疑问词后面必须是一般疑问句结构，所以 be 动词要移到主语前面，因此，where 作表语的句型，就变成了：“表语 + 系动词 + 主语 + 状语？”，这就是典型的倒装结构。作表语也又有时态要求。</p><p>例句：</p><ul><li>Where is your driver?（一般现在时态）</li><li>Where is my money?</li><li>Where are my fans?</li><li>Where are his shoes?</li><li>Where am I now?</li><li>Where are you from?（做介词宾语）</li><li>Where is she from?</li><li>Where do you come from?</li><li>Where did you put your book?（做宾补）</li></ul><h2 id="what-什么" tabindex="-1"><a class="header-anchor" href="#what-什么" aria-hidden="true">#</a> what 什么</h2><p>What 可以充当宾语、表语和主语的作用。</p><ol><li>作宾语，what 做宾语很复杂，因为宾语的情况很多，what 可以做普通及物动词的宾语，也可以做双宾动词的宾语，还可以做动词短语的宾语等等。</li></ol><p>例句：</p><ul><li>What do you eat every day?（一般现在时态）</li><li>What do they learn every day?</li><li>What do my fans drink every night?</li><li>What did you eat just now?（一般过去时态）</li><li>What did they see last night?</li><li>What did you read yesterday?</li><li>What will you eat tomorrow?（一般将来时态）</li><li>What will we do next week?</li><li>What will she borrow tomorrow?</li><li>What is she going to write?</li><li>What are you doing?（现在进行时态）</li><li>What is she cooking?</li><li>What are they selling?</li><li>What have you done?（现在完成时态）</li><li>What has he eaten?</li><li>What has she learned for ten years?</li></ul><ol start="2"><li>做表语，what 做表语和 where 做表语差不多，句型：“what + be + 主语？”，但是做表语用的不多，并且基本上都用在一般现在时态里面，其他时态极少出现。主语大多数都是抽象名词。</li></ol><p>例句：</p><ul><li>What is love?</li><li>What is your name?</li><li>What is your secret?</li><li>What is your plan?</li></ul><h2 id="why-为什么" tabindex="-1"><a class="header-anchor" href="#why-为什么" aria-hidden="true">#</a> why 为什么</h2><p>why 主要充当原因状语，其他作用极少，主谓宾和主系表都可以用。</p><p>例句：</p><ul><li>Why do you learn English?(一般现在时态)</li><li>Why does she buy clothes on taobao.com every month?</li><li>Why do they work so hard?</li><li>Why did you tell me this stroy just now?(一般过去时态)</li><li>Why did you stay up so late last night?</li><li>Why did she cry just now?</li><li>Why will you leave the company next year?（一般将来时态）</li><li>Why are you going to leave the company next year?</li><li>Why will they go to Guangxi next year?</li><li>Why is she singing so loudly?（现在进行时态）</li><li>Why are they screaming?</li><li>Why are they following the man?</li><li>Why are you so sad?（主系表，一般现在时态）</li><li>Why is she so rich?</li><li>Why am I so poor?</li><li>Why are you so angry?</li><li>Why was she late just now?（一般过去时态）</li><li>Why were you silent just now?</li></ul>',26),o=[r];function a(s,d){return i(),l("div",null,o)}const y=e(h,[["render",a],["__file","special-question.html.vue"]]);export{y as default};
